"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["945107"],{916830(e){e.exports=JSON.parse('{"tag":{"label":"auto-populate","permalink":"/sdk/4.9.0/tags/auto-populate","allTagsPath":"/sdk/4.9.0/tags","count":2,"items":[{"id":"guides/assignment-rule-guide","title":"Assignment Rules","description":"Guide for creating ServiceNow Assignment Rules using the Fluent API. Assignment rules automatically populate empty assignmentgroup or assignedto fields on task or task-inherited tables after a record is saved to the database. Assignment rules do not run if these fields already have values. They execute after the insert or update operation completes.","permalink":"/sdk/4.9.0/guides/assignment-rule-guide"},{"id":"guides/data-lookup-guide","title":"Data Lookup","description":"Guide for creating ServiceNow Data Lookup definitions (dl_definition) using the Fluent API. A Data Lookup connects a source table to a configurable matcher table and defines which source fields are used to find a matching row and which values are copied back to the source record. In simple terms form field change, record insert, and record update. If you find yourself reaching for a Business Rule (for insert/update) plus a Client Script (for onChange) to implement the same deterministic field-population logic, use Data Lookup instead.","permalink":"/sdk/4.9.0/guides/data-lookup-guide"}],"unlisted":false}}')}}]);